package com.example.budgettracker.viewmodel

import androidx.lifecycle.ViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update

data class User(
    val username: String,
    val email: String
)

data class AuthState(
    val isLoggedIn: Boolean = false,
    val currentUser: User? = null,
    val errorMessage: String? = null
)

class AuthViewModel : ViewModel() {
    private val _authState = MutableStateFlow(AuthState())
    val authState: StateFlow<AuthState> = _authState.asStateFlow()

    // Simple in-memory user storage for demonstration
    private val registeredUsers = mutableMapOf(
        "admin" to Pair("admin@example.com", "1234")
    )

    fun login(username: String, password: String): Boolean {
        return if (username.isBlank() || password.isBlank()) {
            _authState.update { it.copy(errorMessage = "Username and password cannot be empty") }
            false
        } else if (registeredUsers.containsKey(username)) {
            val (email, storedPassword) = registeredUsers[username]!!
            if (storedPassword == password) {
                _authState.update {
                    it.copy(
                        isLoggedIn = true,
                        currentUser = User(username, email),
                        errorMessage = null
                    )
                }
                true
            } else {
                _authState.update { it.copy(errorMessage = "Invalid password") }
                false
            }
        } else {
            _authState.update { it.copy(errorMessage = "User not found") }
            false
        }
    }

    fun register(username: String, email: String, password: String): Boolean {
        return if (username.isBlank() || email.isBlank() || password.isBlank()) {
            _authState.update { it.copy(errorMessage = "All fields are required") }
            false
        } else if (registeredUsers.containsKey(username)) {
            _authState.update { it.copy(errorMessage = "Username already exists") }
            false
        } else {
            registeredUsers[username] = Pair(email, password)
            _authState.update {
                it.copy(
                    isLoggedIn = true,
                    currentUser = User(username, email),
                    errorMessage = null
                )
            }
            true
        }
    }

    fun logout() {
        _authState.update {
            it.copy(
                isLoggedIn = false,
                currentUser = null,
                errorMessage = null
            )
        }
    }

    fun clearError() {
        _authState.update { it.copy(errorMessage = null) }
    }
}

package com.example.budgettracker.viewmodel



import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.example.budgettracker.data.model.Category
import com.example.budgettracker.data.model.Expense
import com.example.budgettracker.data.repository.CategoryRepository
import com.example.budgettracker.data.repository.ExpenseRepository
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch
import java.time.LocalDate


class ExpenseViewModel(
    private val expenseRepository: ExpenseRepository,
    private val categoryRepository: CategoryRepository
) : ViewModel() {

    // --- UI State ---

    private val _uiState = MutableStateFlow(ExpenseUiState())
    val uiState: StateFlow<ExpenseUiState> = _uiState.asStateFlow()

    // All expenses — observed from database
    val allExpenses: StateFlow<List<Expense>> = expenseRepository
        .allExpenses
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5000),
            initialValue = emptyList()
        )

    // All categories — observed from database
    val allCategories: StateFlow<List<Category>> = categoryRepository
        .allCategories
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5000),
            initialValue = emptyList()
        )

    // Monthly total spending
    private val _monthlyTotal = MutableStateFlow(0.0)
    val monthlyTotal: StateFlow<Double> = _monthlyTotal.asStateFlow()

    init {
        loadMonthlyTotal()
    }

    private fun loadMonthlyTotal() {
        viewModelScope.launch {
            val now = LocalDate.now()
            val startOfMonth = now.withDayOfMonth(1)
            expenseRepository
                .getTotalSpendingInRange(startOfMonth, now)
                .collect { total ->
                    _monthlyTotal.value = total ?: 0.0
                }
        }
    }

    // --- Actions ---

    fun addExpense(expense: Expense) {
        viewModelScope.launch {
            try {
                _uiState.update { it.copy(isLoading = true, errorMessage = null) }
                expenseRepository.insertExpense(expense)
                _uiState.update { it.copy(isLoading = false, saveSuccess = true) }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(isLoading = false, errorMessage = "Failed to save expense: ${e.message}")
                }
            }
        }
    }

    fun deleteExpense(id: Int) {
        viewModelScope.launch {
            try {
                expenseRepository.deleteExpenseById(id)
            } catch (e: Exception) {
                _uiState.update { it.copy(errorMessage = "Failed to delete expense.") }
            }
        }
    }

    fun addCategory(category: Category) {
        viewModelScope.launch {
            try {
                categoryRepository.insertCategory(category)
            } catch (e: Exception) {
                _uiState.update { it.copy(errorMessage = "Failed to save category.") }
            }
        }
    }

    fun clearSaveSuccess() {
        _uiState.update { it.copy(saveSuccess = false) }
    }

    fun clearError() {
        _uiState.update { it.copy(errorMessage = null) }
    }
}

// Holds the current state of the UI (loading, errors, success signals)
data class ExpenseUiState(
    val isLoading: Boolean = false,
    val errorMessage: String? = null,
    val saveSuccess: Boolean = false
)

// Factory to create the ViewModel with dependencies
class ExpenseViewModelFactory(
    private val expenseRepository: ExpenseRepository,
    private val categoryRepository: CategoryRepository
) : ViewModelProvider.Factory {
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(ExpenseViewModel::class.java)) {
            @Suppress("UNCHECKED_CAST")
            return ExpenseViewModel(expenseRepository, categoryRepository) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

package com.example.budgettracker.viewmodel



import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.example.budgettracker.data.model.Category
import com.example.budgettracker.data.model.Expense
import com.example.budgettracker.data.repository.CategoryRepository
import com.example.budgettracker.data.repository.ExpenseRepository
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch
import java.time.LocalDate


class ExpenseViewModel(
    private val expenseRepository: ExpenseRepository,
    private val categoryRepository: CategoryRepository
) : ViewModel() {

    // --- UI State ---

    private val _uiState = MutableStateFlow(ExpenseUiState())
    val uiState: StateFlow<ExpenseUiState> = _uiState.asStateFlow()

    // All expenses — observed from database
    val allExpenses: StateFlow<List<Expense>> = expenseRepository
        .allExpenses
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5000),
            initialValue = emptyList()
        )

    // All categories — observed from database
    val allCategories: StateFlow<List<Category>> = categoryRepository
        .allCategories
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5000),
            initialValue = emptyList()
        )

    // Monthly total spending
    private val _monthlyTotal = MutableStateFlow(0.0)
    val monthlyTotal: StateFlow<Double> = _monthlyTotal.asStateFlow()

    // Filter states
    private val _selectedDateRange = MutableStateFlow<Pair<LocalDate, LocalDate>?>(null)
    val selectedDateRange: StateFlow<Pair<LocalDate, LocalDate>?> = _selectedDateRange.asStateFlow()

    private val _selectedCategoryId = MutableStateFlow<Int?>(null)
    val selectedCategoryId: StateFlow<Int?> = _selectedCategoryId.asStateFlow()

    // Filtered expenses
    val filteredExpenses: StateFlow<List<Expense>> = combine(
        allExpenses,
        _selectedDateRange,
        _selectedCategoryId
    ) { expenses, dateRange, categoryId ->
        var filtered = expenses

        // Apply date range filter
        if (dateRange != null) {
            filtered = filtered.filter { expense ->
                !expense.date.isBefore(dateRange.first) && !expense.date.isAfter(dateRange.second)
            }
        }

        // Apply category filter
        if (categoryId != null) {
            filtered = filtered.filter { it.categoryId == categoryId }
        }

        filtered
    }.stateIn(
        scope = viewModelScope,
        started = SharingStarted.WhileSubscribed(5000),
        initialValue = emptyList()
    )

    init {
        loadMonthlyTotal()
    }

    private fun loadMonthlyTotal() {
        viewModelScope.launch {
            val now = LocalDate.now()
            val startOfMonth = now.withDayOfMonth(1)
            expenseRepository
                .getTotalSpendingInRange(startOfMonth, now)
                .collect { total ->
                    _monthlyTotal.value = total ?: 0.0
                }
        }
    }

    // --- Actions ---

    fun addExpense(expense: Expense) {
        viewModelScope.launch {
            try {
                _uiState.update { it.copy(isLoading = true, errorMessage = null) }
                expenseRepository.insertExpense(expense)
                _uiState.update { it.copy(isLoading = false, saveSuccess = true) }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(isLoading = false, errorMessage = "Failed to save expense: ${e.message}")
                }
            }
        }
    }

    fun deleteExpense(id: Int) {
        viewModelScope.launch {
            try {
                expenseRepository.deleteExpenseById(id)
            } catch (e: Exception) {
                _uiState.update { it.copy(errorMessage = "Failed to delete expense.") }
            }
        }
    }

    fun addCategory(category: Category) {
        viewModelScope.launch {
            try {
                categoryRepository.insertCategory(category)
            } catch (e: Exception) {
                _uiState.update { it.copy(errorMessage = "Failed to save category.") }
            }
        }
    }

    fun clearSaveSuccess() {
        _uiState.update { it.copy(saveSuccess = false) }
    }

    fun clearError() {
        _uiState.update { it.copy(errorMessage = null) }
    }

    // --- Filter Actions ---

    fun setDateRange(startDate: LocalDate, endDate: LocalDate) {
        _selectedDateRange.value = Pair(startDate, endDate)
    }

    fun clearDateRange() {
        _selectedDateRange.value = null
    }

    fun setCategoryFilter(categoryId: Int?) {
        _selectedCategoryId.value = categoryId
    }

    fun clearCategoryFilter() {
        _selectedCategoryId.value = null
    }

    fun clearAllFilters() {
        _selectedDateRange.value = null
        _selectedCategoryId.value = null
    }
}

// Holds the current state of the UI (loading, errors, success signals)
data class ExpenseUiState(
    val isLoading: Boolean = false,
    val errorMessage: String? = null,
    val saveSuccess: Boolean = false
)

// Factory to create the ViewModel with dependencies
class ExpenseViewModelFactory(
    private val expenseRepository: ExpenseRepository,
    private val categoryRepository: CategoryRepository
) : ViewModelProvider.Factory {
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(ExpenseViewModel::class.java)) {
            @Suppress("UNCHECKED_CAST")
            return ExpenseViewModel(expenseRepository, categoryRepository) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

package com.example.budgettracker.viewmodel

import androidx.compose.runtime.collectAsState
import junit.framework.TestCase.assertEquals
import junit.framework.TestCase.assertFalse
import junit.framework.TestCase.assertNotNull
import junit.framework.TestCase.assertNull
import junit.framework.TestCase.assertTrue
import org.junit.Before
import org.junit.Test

class AuthViewModelTest {

    private lateinit var authViewModel: AuthViewModel

    @Before
    fun setUp() {
        authViewModel = AuthViewModel()
    }

    @Test
    fun testInitialState() {
        val authState = authViewModel.authState.value
        assertFalse(authState.isLoggedIn)
        assertNull(authState.currentUser)
        assertNull(authState.errorMessage)
    }

    @Test
    fun testLoginWithValidCredentials() {
        val result = authViewModel.login("admin", "1234")

        assertTrue(result)
        assertTrue(authViewModel.authState.value.isLoggedIn)
        assertNotNull(authViewModel.authState.value.currentUser)
        assertEquals("admin", authViewModel.authState.value.currentUser?.username)
        assertNull(authViewModel.authState.value.errorMessage)
    }

    @Test
    fun testLoginWithInvalidPassword() {
        val result = authViewModel.login("admin", "wrongpassword")

        assertFalse(result)
        assertFalse(authViewModel.authState.value.isLoggedIn)
        assertNotNull(authViewModel.authState.value.errorMessage)
        assertTrue(authViewModel.authState.value.errorMessage!!.contains("password"))
    }

    @Test
    fun testLoginWithNonExistentUser() {
        val result = authViewModel.login("nonexistent", "1234")

        assertFalse(result)
        assertFalse(authViewModel.authState.value.isLoggedIn)
        assertNotNull(authViewModel.authState.value.errorMessage)
        assertTrue(authViewModel.authState.value.errorMessage!!.contains("not found"))
    }

    @Test
    fun testLoginWithEmptyCredentials() {
        val result = authViewModel.login("", "")

        assertFalse(result)
        assertFalse(authViewModel.authState.value.isLoggedIn)
        assertNotNull(authViewModel.authState.value.errorMessage)
    }

    @Test
    fun testRegisterWithValidData() {
        val result = authViewModel.register("newuser", "newuser@example.com", "password123")

        assertTrue(result)
        assertTrue(authViewModel.authState.value.isLoggedIn)
        assertNotNull(authViewModel.authState.value.currentUser)
        assertEquals("newuser", authViewModel.authState.value.currentUser?.username)
        assertEquals("newuser@example.com", authViewModel.authState.value.currentUser?.email)
    }

    @Test
    fun testRegisterWithDuplicateUsername() {
        // First registration
        authViewModel.register("testuser", "test@example.com", "password")
        authViewModel.logout()

        // Try to register again with same username
        val result = authViewModel.register("testuser", "another@example.com", "password")

        assertFalse(result)
        assertFalse(authViewModel.authState.value.isLoggedIn)
        assertNotNull(authViewModel.authState.value.errorMessage)
        assertTrue(authViewModel.authState.value.errorMessage!!.contains("already exists"))
    }

    @Test
    fun testRegisterWithEmptyFields() {
        val result = authViewModel.register("", "email@example.com", "password")

        assertFalse(result)
        assertFalse(authViewModel.authState.value.isLoggedIn)
        assertNotNull(authViewModel.authState.value.errorMessage)
    }

    @Test
    fun testLogout() {
        // First login
        authViewModel.login("admin", "1234")
        assertTrue(authViewModel.authState.value.isLoggedIn)

        // Then logout
        authViewModel.logout()

        assertFalse(authViewModel.authState.value.isLoggedIn)
        assertNull(authViewModel.authState.value.currentUser)
        assertNull(authViewModel.authState.value.errorMessage)
    }

    @Test
    fun testClearError() {
        authViewModel.login("admin", "wrongpassword")
        assertNotNull(authViewModel.authState.value.errorMessage)

        authViewModel.clearError()

        assertNull(authViewModel.authState.value.errorMessage)
    }
}

